// Retrieve results and total count from the current HTTP Request execution
const newResults = $node["Get Xray Test cases (not including Preconditions)"].json.data.getTests.results || [];
const total = $node["Get Xray Test cases (not including Preconditions)"].json.data.getTests.total || 0;

// Initialize variables for data accumulation and pagination offset
let accumulated = [];
let currentStart = 0;

try {
  // Access data from this node's previous execution to maintain state
  const lastExecution = $node["Aggregate Data"].json;
  accumulated = lastExecution.allResults || [];
  currentStart = lastExecution.start || 0;
} catch (e) {
  // Fallback for the first iteration if no previous state exists
  accumulated = [];
  currentStart = 0;
}

// Merge new results into the existing collection and calculate the next offset
const finalResults = accumulated.concat(newResults);
const nextStart = currentStart + 100;

return {
  start: nextStart,
  allResults: finalResults,
  total: total,
  done: nextStart >= total
};

// Extract accumulated results from the main loop's final execution
const allData = $('Aggregate Data').last().json.allResults;
const callTestIds = new Set();

// Iterate through test cases and steps to collect unique callTestIssueId values
allData.forEach(test => {
  const steps = test.steps || [];
  steps.forEach(step => {
    if (step.callTestIssueId) {
      callTestIds.add(step.callTestIssueId);
    }
  });
});

const idArray = Array.from(callTestIds);
const batchSize = 100; // Xray limit for batch queries
const results = [];

// Partition the ID list into batches to comply with API constraints
for (let i = 0; i < idArray.length; i += batchSize) {
  const batch = idArray.slice(i, i + batchSize);
  results.push({
    json: {
      ids: batch.join(', ') // Format IDs as a comma-separated string for the request
    }
  });
}

return results;

