// Retrieve the accumulated results from the main loop's final execution
const results = $('Aggregate Data').last().json.allResults;

// Build a lookup map for Jira Keys across all execution items from the Fetch node
const keyMap = {};
const allFetchItems = $('Fetch CalledTestID Keys').all(); 

allFetchItems.forEach(item => {
  const batchResults = item.json.data.getTests.results || [];
  batchResults.forEach(res => {
    if (res.jira) {
      keyMap[res.jira.id] = res.jira.key;
    }
  });
});

let rows = [];

// Helper function to sanitize and format step content by removing Jira-specific markup
const cleanStepContent = (text) => {
  if (!text) return "";
  return text
    .replace(/\{color:[^}]+\}/g, "").replace(/\{color\}/g, "")
    .replace(/\{code:[^}]+\}/g, "").replace(/\{code\}/g, "")
    .replace(/\{noformat\}/g, "")
    .replace(/^([\s]*)([*#-]+)\s+/gm, (match, space, bullets) => {
      const level = bullets.length;
      return "   ".repeat(level - 1) + "- "; 
    })
    .replace(/\[([^|\]]+)\|([^\]]+)\]/g, '"$2"')
    .replace(/\[(http[^\]]+)\]/g, '"$1"')
    .replace(/[*_~^]/g, "")
    .replace(/\\r\\n/g, "\n")
    .trim();
};

// Map raw results into structured rows for final export or reporting
for (const test of results) {
  const steps = test.steps || [];
  const jira = test.jira || {};

  if (steps.length > 0) {
    steps.forEach((step, i) => {
      // Resolve the pre-condition key using the previously built lookup map
      const preConditionKey = keyMap[step.callTestIssueId] || step.callTestIssueId || "";

      rows.push({
        "Test case ID": i === 0 ? jira.key : "",
        "Description": i === 0 ? jira.summary : "", 
        "Call-test": preConditionKey,
        "Test data": step.data || "", 
        "Steps": cleanStepContent(step.action),
        "Expected Result": cleanStepContent(step.result),
        "Status": i === 0 ? "Passed" : ""
      });
    });
  } else {
    // Handle test cases without steps
    rows.push({
      "Test case ID": jira.key,
      "Description": jira.summary,
      "Steps": "",
      "Status": "Passed"
    });
  }
}

return rows;
